class FoodRatings {

    private Map<String, Integer> foodRating;
    private Map<String, String> foodCuisine;
    private Map<String, TreeSet<Food>> cuisineFoods;

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        foodRating = new HashMap<>();
        foodCuisine = new HashMap<>();
        cuisineFoods = new HashMap<>();

        for (int i = 0; i < foods.length; i++) {
            foodRating.put(foods[i], ratings[i]);
            foodCuisine.put(foods[i], cuisines[i]);

            cuisineFoods.computeIfAbsent(cuisines[i], k -> new TreeSet<>((a, b) -> a.rating == b.rating ? a.name.compareTo(b.name) : Integer.compare(b.rating, a.rating)));
            cuisineFoods.get(cuisines[i]).add(new Food(foods[i], ratings[i]));
        }
    }

    public void changeRating(String food, int newRating) {
        String cuisine = foodCuisine.get(food);
        TreeSet<Food> foods = cuisineFoods.get(cuisine);
        foods.remove(new Food(food, foodRating.get(food)));
        foods.add(new Food(food, newRating));
        foodRating.put(food, newRating);
    }

    public String highestRated(String cuisine) {
        return cuisineFoods.get(cuisine).first().name;
    }

    private static class Food {
        String name;
        int rating;

        Food(String name, int rating) {
            this.name = name;
            this.rating = rating;
        }
    }
}

